INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("えへへ、どーもどーも。\nいや素直に嬉しいですよね、\nわざわざこんな準備までしてもらって。\nその気持ちだけでホント幸せです！", 10, 0, 11, 21314065, 1, 21314, 0, 0.5, 1, 110911);
