INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("て、手作りケーキっ！？\n陛下が、わたくしのためにっ！？\nなんという光栄……！　ケーキがまるで\n金銀財宝のように輝いて見えますわ！", 10, 0, 11, 21714058, 1, 21714, 0, 0.5, 1, 118011);
