INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("でも、たくさん迷惑をかけているし。\nこんなふうにお祝いをしてもらう\n資格なんて……私には……", 10, 0, 11, 30314075, 1, 30314, 0, 0.5, 1, 106411);
