INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("それならプリンがいいの～！\nこのケーキと同じくらい、でっかい\nプリンが食べたいの～！", 10, 0, 11, 31114076, 1, 31114, 0, 0.5, 1, 100711);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 91, 31114077, "", 31114, "", "", "", 0);
