INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("……ありがとうございます。\nわざわざ占ったりしませんが、\nこういう幸せな日々が、\nずっと続くことを願っています。", 10, 0, 11, 31114100, 1, 31114, 0, 0.5, 1, 103111);
